import ast, sys

for filepath in ['src/agent.py', 'src/cli.py', 'src/prompt.py', 'src/memory.py', 'src/tools.py']:
    with open(filepath) as f:
        tree = ast.parse(f.read())

    imports = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                imports.append((alias.asname or alias.name, node.lineno))
        elif isinstance(node, ast.ImportFrom):
            for alias in node.names:
                imports.append((alias.asname or alias.name, node.lineno))

    # Get all names used in the file
    with open(filepath) as f:
        content = f.read()

    unused = []
    for name, lineno in imports:
        # Simple heuristic: count occurrences beyond the import line
        # This is imprecise but helpful for discovery
        parts = content.split('\n')
        count = 0
        for i, line in enumerate(parts):
            if i != lineno - 1 and name in line:
                count += 1
        if count == 0:
            unused.append((name, lineno))

    if unused:
        print(f'\n{filepath}:')
        for name, lineno in unused:
            print(f'  line {lineno}: {name} (possibly unused)')
